using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace ApiMcpServer;

/// <summary>
/// MCP tools that wrap a REST API via HttpClient.
/// Non-static class — services are injected through the constructor.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool(ReadOnly = true), Description("Get a single item by its numeric ID.")]
    public async Task<string> GetItem(
        [Description("The numeric ID of the item to retrieve")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching item {Id}", id);
        var response = await httpClient.GetAsync($"/posts/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }

    [McpServerTool(ReadOnly = true), Description("List items, optionally filtered by user ID.")]
    public async Task<string> ListItems(
        [Description("Optional user ID to filter items by author")] int? userId = null,
        CancellationToken cancellationToken = default)
    {
        var url = userId.HasValue ? $"/posts?userId={userId}" : "/posts";
        logger.LogInformation("Listing items from {Url}", url);
        var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }

    [McpServerTool(Destructive = false, ReadOnly = false),
     Description("Create a new item with a title and body, attributed to a user.")]
    public async Task<string> CreateItem(
        [Description("Title of the new item")] string title,
        [Description("Body content of the new item")] string body,
        [Description("User ID of the author")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating item for user {UserId}", userId);
        var payload = new { title, body, userId };
        var content = new StringContent(
            JsonSerializer.Serialize(payload), System.Text.Encoding.UTF8, "application/json");
        var response = await httpClient.PostAsync("/posts", content, cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }
}

